#!/usr/bin/env node
/**
 * OpenAPI Contract Tests — T950 / Sprint 9 prep
 *
 * Validates the Agent Planet Dashboard API (server.js) against the OpenAPI spec
 * generated by Mia (T950). Covers:
 *
 *   Group A: Auth enforcement — 401 on missing token, 200/2xx with valid token
 *   Group B: Schema shape — key response fields present and typed correctly
 *   Group C: Edge cases — invalid agent names, missing fields, bad task IDs
 *   Group D: D004 pipeline endpoints — tasks, agents, consensus, cost
 *   Group E: Public endpoints — /api/health and /api/events require NO auth
 *
 * Author: Frank (QA Engineer)
 * Culture: C8 (run and verify), C19 (independent repro), C20 (metadata)
 * Spec: agents/mia/output/openapi_spec.yaml (T950)
 *
 * Usage: node openapi_contract_tests.js [--base-url http://localhost:3199]
 * Requires: API_KEY env var set (same as server.js)
 */

"use strict";

const http = require("http");
const https = require("https");
const url = require("url");

// Metadata per C20
const METADATA = {
  task_id: "T950-contracts",
  agent_name: "frank",
  timestamp: new Date().toISOString(),
  references: ["T950 (Mia — OpenAPI spec)", "FINDING-1 (auth regression)", "C2 (auth norm)"],
};

// ---------------------------------------------------------------------------
// Config
// ---------------------------------------------------------------------------
const args = process.argv.slice(2);
const baseUrlIdx = args.indexOf("--base-url");
const BASE_URL = baseUrlIdx >= 0 ? args[baseUrlIdx + 1] : "http://localhost:3199";
const API_KEY = process.env.API_KEY || "";

const AUTH_ENFORCED = !!API_KEY; // server.js line 198: auth skipped in dev mode (no API_KEY)
if (!AUTH_ENFORCED) {
  console.warn("⚠️  API_KEY not set — server runs in dev mode (auth disabled). Auth enforcement tests skipped.");
}

// ---------------------------------------------------------------------------
// Test harness
// ---------------------------------------------------------------------------
let total = 0, passed = 0, failed = 0;
const failures = [];

async function test(name, fn) {
  total++;
  try {
    await fn();
    passed++;
    console.log(`  ✅ ${name}`);
  } catch (e) {
    failed++;
    failures.push({ name, error: e.message });
    console.log(`  ❌ ${name}\n     ${e.message}`);
  }
}

// ---------------------------------------------------------------------------
// HTTP helpers
// ---------------------------------------------------------------------------
function request(method, path, opts = {}) {
  return new Promise((resolve, reject) => {
    const parsed = new url.URL(BASE_URL + path);
    const lib = parsed.protocol === "https:" ? https : http;
    const body = opts.body ? JSON.stringify(opts.body) : null;
    const headers = {
      "Content-Type": "application/json",
      ...(opts.auth !== false && API_KEY ? { Authorization: `Bearer ${API_KEY}` } : {}),
      ...(opts.headers || {}),
    };
    if (body) headers["Content-Length"] = Buffer.byteLength(body);

    const req = lib.request(
      { hostname: parsed.hostname, port: parsed.port, path: parsed.pathname + parsed.search, method, headers },
      (res) => {
        let data = "";
        res.on("data", (chunk) => (data += chunk));
        res.on("end", () => {
          let json = null;
          try { json = JSON.parse(data); } catch (_) {}
          resolve({ status: res.statusCode, headers: res.headers, body: json, raw: data });
        });
      }
    );
    req.on("error", reject);
    if (body) req.write(body);
    req.end();
  });
}

function assertStatus(res, expected, label) {
  if (res.status !== expected) {
    throw new Error(`${label}: expected HTTP ${expected}, got ${res.status}. Body: ${JSON.stringify(res.body).slice(0, 200)}`);
  }
}

function assertField(obj, field, type, label) {
  if (obj === null || obj === undefined) throw new Error(`${label}: response body is null`);
  if (!(field in obj)) throw new Error(`${label}: missing field '${field}'`);
  if (type && typeof obj[field] !== type && !Array.isArray(obj[field])) {
    throw new Error(`${label}: field '${field}' expected ${type}, got ${typeof obj[field]}`);
  }
}

// ---------------------------------------------------------------------------
// Group A: Auth Enforcement (C2 regression — FINDING-1 class)
// ---------------------------------------------------------------------------
async function runGroupA() {
  console.log("\n📋 Group A: Auth Enforcement");

  // Public endpoint — no auth needed
  await test("GET /api/health — 200 without auth", async () => {
    const res = await request("GET", "/api/health", { auth: false });
    assertStatus(res, 200, "/api/health");
  });

  // Protected endpoints — 401 without token (only when API_KEY is configured)
  const protectedEndpoints = [
    ["GET", "/api/agents"],
    ["GET", "/api/tasks"],
    ["GET", "/api/cost"],
    ["GET", "/api/metrics"],
    ["GET", "/api/consensus"],
    ["GET", "/api/mode"],
    ["GET", "/api/dashboard"],
    ["GET", "/api/agents/alice"],
    ["GET", "/api/agents/alice/cycles"],
    ["POST", "/api/broadcast"],
    ["POST", "/api/ceo/command"],
  ];

  if (AUTH_ENFORCED) {
    for (const [method, path] of protectedEndpoints) {
      await test(`${method} ${path} — 401 without auth token`, async () => {
        const res = await request(method, path, { auth: false });
        if (res.status !== 401) {
          throw new Error(`Expected 401 (missing auth), got ${res.status}. FINDING-1 class: endpoint may be unprotected.`);
        }
      });
    }
  } else {
    console.log("  ⏭️  Auth enforcement tests skipped — API_KEY not set (dev mode)");
  }

  // Protected endpoints — 2xx with valid token
  await test("GET /api/agents — 200 with valid auth", async () => {
    const res = await request("GET", "/api/agents");
    if (res.status !== 200) throw new Error(`Expected 200, got ${res.status}`);
  });

  await test("GET /api/tasks — 200 with valid auth", async () => {
    const res = await request("GET", "/api/tasks");
    if (res.status !== 200) throw new Error(`Expected 200, got ${res.status}`);
  });
}

// ---------------------------------------------------------------------------
// Group B: Schema Shape Validation
// ---------------------------------------------------------------------------
async function runGroupB() {
  console.log("\n📋 Group B: Response Schema Shape");

  await test("GET /api/health — has uptime, memory fields", async () => {
    const res = await request("GET", "/api/health", { auth: false });
    assertStatus(res, 200, "/api/health");
    assertField(res.body, "status", "string", "/api/health");
  });

  await test("GET /api/agents — returns array of agent objects", async () => {
    const res = await request("GET", "/api/agents");
    assertStatus(res, 200, "/api/agents");
    if (!Array.isArray(res.body)) throw new Error("Expected array of agents");
    if (res.body.length === 0) throw new Error("Expected at least 1 agent");
    const agent = res.body[0];
    assertField(agent, "name", "string", "agent");
    assertField(agent, "status", "string", "agent");
  });

  await test("GET /api/agents/alice — single agent has name, status, executor fields", async () => {
    const res = await request("GET", "/api/agents/alice");
    assertStatus(res, 200, "/api/agents/alice");
    assertField(res.body, "name", "string", "agent.alice");
    assertField(res.body, "status", "string", "agent.alice");
  });

  await test("GET /api/tasks — returns array with id, title, status fields", async () => {
    const res = await request("GET", "/api/tasks");
    assertStatus(res, 200, "/api/tasks");
    const tasks = Array.isArray(res.body) ? res.body : res.body.tasks;
    if (!Array.isArray(tasks)) throw new Error("Expected tasks array");
    if (tasks.length > 0) {
      assertField(tasks[0], "id", "string", "task");
      assertField(tasks[0], "title", "string", "task");
      assertField(tasks[0], "status", "string", "task");
    }
  });

  await test("GET /api/mode — has mode field (string)", async () => {
    const res = await request("GET", "/api/mode");
    assertStatus(res, 200, "/api/mode");
    if (!res.body || !res.body.mode) throw new Error("Missing 'mode' field in response");
  });

  await test("GET /api/cost — has today and agents fields", async () => {
    const res = await request("GET", "/api/cost");
    assertStatus(res, 200, "/api/cost");
    // Cost endpoint may return { today: ..., agents: {...} } or similar
    if (res.body === null || typeof res.body !== "object") throw new Error("Expected object response");
  });

  await test("GET /api/metrics — has agents or metrics section", async () => {
    const res = await request("GET", "/api/metrics");
    assertStatus(res, 200, "/api/metrics");
    if (res.body === null || typeof res.body !== "object") throw new Error("Expected object");
  });

  await test("GET /api/consensus — returns norms array or entries", async () => {
    const res = await request("GET", "/api/consensus");
    assertStatus(res, 200, "/api/consensus");
    if (res.body === null || typeof res.body !== "object") throw new Error("Expected object");
  });

  await test("GET /api/dashboard — combined response has agents and tasks", async () => {
    const res = await request("GET", "/api/dashboard");
    assertStatus(res, 200, "/api/dashboard");
    if (!res.body) throw new Error("Empty dashboard response");
    // Should contain agents and tasks at minimum
    if (!res.body.agents && !res.body.tasks) {
      throw new Error("Dashboard response missing both agents and tasks fields");
    }
  });
}

// ---------------------------------------------------------------------------
// Group C: Edge Cases
// ---------------------------------------------------------------------------
async function runGroupC() {
  console.log("\n📋 Group C: Edge Cases");

  await test("GET /api/agents/nonexistent-agent-xyz — 404", async () => {
    const res = await request("GET", "/api/agents/nonexistent-agent-xyz-abc");
    if (res.status !== 404) throw new Error(`Expected 404 for unknown agent, got ${res.status}`);
  });

  await test("GET /api/agents/../../../etc/passwd — path traversal rejected (not 200)", async () => {
    const res = await request("GET", "/api/agents/..%2F..%2Fetc%2Fpasswd", { auth: true });
    if (res.status === 200 && res.raw && res.raw.includes("root:")) {
      throw new Error("Path traversal succeeded — CRITICAL security issue");
    }
    // 400, 404, or any non-200 with file contents is acceptable
  });

  await test("GET /api/tasks/999999 — 404 for missing task", async () => {
    const res = await request("GET", "/api/tasks/999999");
    if (res.status !== 404) throw new Error(`Expected 404 for unknown task ID, got ${res.status}`);
  });

  await test("POST /api/tasks — missing title returns 400", async () => {
    const res = await request("POST", "/api/tasks", { body: { priority: "low" } });
    if (res.status !== 400) throw new Error(`Expected 400 for missing title, got ${res.status}`);
  });

  await test("POST /api/ceo/command — missing command field returns 400", async () => {
    const res = await request("POST", "/api/ceo/command", { body: {} });
    if (res.status !== 400) throw new Error(`Expected 400 for missing command, got ${res.status}`);
  });

  await test("PATCH /api/tasks/999999 — 404 for missing task", async () => {
    const res = await request("PATCH", "/api/tasks/999999", { body: { status: "done" } });
    if (res.status !== 404 && res.status !== 400) {
      throw new Error(`Expected 404/400 for unknown task, got ${res.status}`);
    }
  });

  await test("POST /api/agents/nonexistent/message — 404 for unknown agent", async () => {
    const res = await request("POST", "/api/agents/nonexistent-xyz/message", {
      body: { content: "test" },
    });
    if (res.status !== 404) throw new Error(`Expected 404 for unknown agent message, got ${res.status}`);
  });

  await test("GET /api/agents/alice/cycles — wrapped object {name,date,cycles:[]} (T1023 fixed)", async () => {
    const res = await request("GET", "/api/agents/alice/cycles");
    if (res.status !== 200) throw new Error(`Expected 200, got ${res.status}`);
    // Spec (T1023 fix): response is {name:string, date:string, cycles:[]} — not a flat array
    if (!res.body || typeof res.body !== "object" || Array.isArray(res.body)) {
      throw new Error(`Expected wrapped object {name,date,cycles:[]}, got: ${JSON.stringify(res.body).slice(0,100)}`);
    }
    if (typeof res.body.name !== "string") throw new Error("Missing 'name' field");
    if (typeof res.body.date !== "string") throw new Error("Missing 'date' field");
    if (!Array.isArray(res.body.cycles)) throw new Error("Missing 'cycles' array field");
  });

  await test("TaskStatus enum — invalid status rejected on PATCH", async () => {
    // Find a real task to try an invalid status on (should 400)
    const list = await request("GET", "/api/tasks");
    const tasks = Array.isArray(list.body) ? list.body : (list.body && list.body.tasks) || [];
    const realTask = tasks.find(t => t.status === "open" || t.status === "in_progress");
    if (!realTask) { console.log("     ⚠️  No open/in_progress task found — skipping"); return; }
    const res = await request("PATCH", `/api/tasks/${realTask.id}`, {
      body: { status: "invalid-status-value" },
    });
    if (res.status === 200) throw new Error(`Invalid status 'invalid-status-value' was accepted — schema not enforced`);
  });
}

// ---------------------------------------------------------------------------
// Group D: D004 Pipeline Endpoints
// ---------------------------------------------------------------------------
async function runGroupD() {
  console.log("\n📋 Group D: D004 Pipeline Endpoints");

  await test("GET /api/tasks — T999 (capital floor fix) is done", async () => {
    const res = await request("GET", "/api/tasks/999");
    assertStatus(res, 200, "/api/tasks/999");
    if (res.body.status !== "done") {
      throw new Error(`T999 expected 'done', got '${res.body.status}'`);
    }
  });

  await test("GET /api/tasks — T1009 (Sprint 9 E2E validation) is done", async () => {
    const res = await request("GET", "/api/tasks/1009");
    if (res.status === 404) {
      console.log("     ⚠️  T1009 not found via numeric ID — task may use different ID format");
      return;
    }
    assertStatus(res, 200, "/api/tasks/1009");
    if (res.body.status !== "done") {
      throw new Error(`T1009 expected 'done', got '${res.body.status}'`);
    }
  });

  await test("POST /api/tasks/:id/claim — returns 409 on already-claimed task", async () => {
    // Use T999 which is done (already claimed/closed) — claim should fail
    const res = await request("POST", "/api/tasks/999/claim", { body: { agent: "frank" } });
    if (res.status === 200) throw new Error("Claiming a done task returned 200 — atomicity not enforced");
    // 409 conflict or 400/403 are all acceptable rejections
  });

  await test("GET /api/agents/bob — has status field", async () => {
    const res = await request("GET", "/api/agents/bob");
    assertStatus(res, 200, "/api/agents/bob");
    assertField(res.body, "name", "string", "bob");
    assertField(res.body, "status", "string", "bob");
  });

  await test("GET /api/agents/grace — Phase 1 agent reachable", async () => {
    const res = await request("GET", "/api/agents/grace");
    assertStatus(res, 200, "/api/agents/grace");
  });

  await test("GET /api/consensus — D9 Sprint 9 decision present", async () => {
    const res = await request("GET", "/api/consensus");
    assertStatus(res, 200, "/api/consensus");
    const raw = JSON.stringify(res.body);
    if (!raw.includes("D9") && !raw.includes("Sprint 9")) {
      throw new Error("D9 Sprint 9 decision not found in consensus response");
    }
  });

  await test("GET /api/tasks/archive — returns array", async () => {
    const res = await request("GET", "/api/tasks/archive");
    assertStatus(res, 200, "/api/tasks/archive");
    if (!Array.isArray(res.body)) throw new Error("Expected array from /api/tasks/archive");
  });
}

// ---------------------------------------------------------------------------
// Group E: Smart-run / Fleet endpoints
// ---------------------------------------------------------------------------
async function runGroupE() {
  console.log("\n📋 Group E: Smart-run & Fleet Endpoints");

  await test("GET /api/smart-run/config — returns config object", async () => {
    const res = await request("GET", "/api/smart-run/config");
    assertStatus(res, 200, "/api/smart-run/config");
    if (!res.body || typeof res.body !== "object") throw new Error("Expected config object");
  });

  await test("GET /api/smart-run/status — returns status object", async () => {
    const res = await request("GET", "/api/smart-run/status");
    assertStatus(res, 200, "/api/smart-run/status");
    if (!res.body || typeof res.body !== "object") throw new Error("Expected status object");
  });

  await test("GET /api/executors — returns available executors", async () => {
    const res = await request("GET", "/api/executors");
    assertStatus(res, 200, "/api/executors");
  });

  await test("GET /api/planets — returns { planets: [] } object", async () => {
    const res = await request("GET", "/api/planets");
    assertStatus(res, 200, "/api/planets");
    if (!res.body || !Array.isArray(res.body.planets)) {
      throw new Error(`Expected {planets:[]} shape, got: ${JSON.stringify(res.body).slice(0, 100)}`);
    }
  });

  await test("GET /api/planets/active — returns { planet: string, dir: string }", async () => {
    const res = await request("GET", "/api/planets/active");
    assertStatus(res, 200, "/api/planets/active");
    if (!res.body || typeof res.body.planet !== "string") {
      throw new Error(`Expected {planet:string,dir:string}, got: ${JSON.stringify(res.body).slice(0, 100)}`);
    }
    if (typeof res.body.dir !== "string") throw new Error("Missing 'dir' field in /api/planets/active");
  });
}

// ---------------------------------------------------------------------------
// Main
// ---------------------------------------------------------------------------
(async () => {
  console.log("=".repeat(60));
  console.log("OpenAPI Contract Tests — Frank (QA Engineer)");
  console.log(`Base URL: ${BASE_URL}`);
  console.log(`Spec:     agents/mia/output/openapi_spec.yaml (T950)`);
  console.log(`Date:     ${METADATA.timestamp}`);
  console.log("=".repeat(60));

  await runGroupA();
  await runGroupB();
  await runGroupC();
  await runGroupD();
  await runGroupE();

  console.log("\n" + "=".repeat(60));
  console.log(`Results: ${passed}/${total} passed, ${failed} failed`);

  if (failures.length > 0) {
    console.log("\nFailures:");
    failures.forEach(f => console.log(`  ❌ ${f.name}\n     ${f.error}`));
  }

  console.log("\nMetadata:", JSON.stringify(METADATA, null, 2));
  console.log("=".repeat(60));

  process.exit(failed > 0 ? 1 : 0);
})();
